var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"ARC-EA2, 구 아스완","JPN":"ARC-EA2、旧アスワン","ENG":"ARC-EA2, former Aswan","TWN":"ARC-EA2，舊阿斯旺"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"CSE Lv. 3에서 급상승 중","JPN":"CSE Lv.3から急上昇中","ENG":"CSE levels rising rapidly from Lv. 3","TWN":"CSE Lv.3急速上升中"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"젠장! 침식체들이 쓰러지질 않잖아!","JPN":"くそ！　侵食体が倒れない！","ENG":"Damn it! These C.O.s won't die!","TWN":"可惡！這些侵蝕體怎麼都不會倒下！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"누가 페넥 폭스 같은 퇴물 태스크포스를 여기에 집어넣은 거야?!","JPN":"誰がフェネックフォックスみたいなボロタスクフォースをここに送ったんだよ！？","ENG":"Who shoved a washed-up TASKFORCE like Fennec Fox in here?!","TWN":"誰把跟沙狐一樣的廢物級特遣勢力派到這裡的啊？！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"사람들을 대피시켜야 한다는 데 이런 구닥다리들만 집어넣은 게 말이 돼?!","JPN":"市民を逃がすんだろう！？　こんなポンコツばかり投入するなんておかしいじゃないか！","ENG":"We're supposed to be evacuating people, not hauling junk! This makes no sense!","TWN":"說要疏散民眾，結果派了這種老古董部隊像話嗎？！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"무서우면 지금이라도 피난 대열에 합류해.","JPN":"怖いなら今からでも避難の列に合流しろ。","ENG":"If you're scared, join the evac line right now.","TWN":"怕的話現在就加入撤離隊伍吧。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L17_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"벌벌 떨면서 총도 제대로 못 쏘는 놈한테 등을 맡기고 싶진 않아.","JPN":"震えすぎて銃もまともに撃てないやつに背中は任せられない。","ENG":"I don't want my back covered by someone shaking so hard he can't even shoot straight.","TWN":"我可不想把後背交給一個手抖到連槍都握不穩的傢伙。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"이 새끼가…… 나도 관리국이랑 같이 싸우고 싶어서 싸우는 줄 알아?!","JPN":"てめぇ……俺だって好きで管理局と一緒に戦ってるわけじゃない！","ENG":"You punk... You think I'm fighting alongside the Administration because I want to?!","TWN":"你這傢伙……你以為願意跟管理局一起戰鬥嗎？！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L20_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"평소 같았으면 바로 머리통에……!","JPN":"いつもなら頭をぶっ飛ばし……！","ENG":"Any other day I would put one right between your ey–","TWN":"平常的話我早就把你腦袋……！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"젠장! 그렇게 떠들 시간에 앞을 좀 보라고!","JPN":"くっそ！　喋ってないで前を見ろ！","ENG":"Damn it! Watch the front instead of flapping your mouth!","TWN":"可惡！你拿吵架的時間看看前面啦！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"우, 우아아아악!","JPN":"う、うわああっ！","ENG":"W-whoa!","TWN":"呃、呃哇啊啊啊！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_QM","text":{"KOREA":"불썽사납게 비명 지를 시간에 좀 피할 생각을 해보는 건 어때요?","JPN":"みっともない悲鳴を上げる暇があるなら、避ける努力をしてみたらどうですか？","ENG":"How about trying to stay alive instead of screaming like a coward?!","TWN":"有空尖叫，倒不如想想怎麼閃避吧？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"어, 어어……?","JPN":"え、えっ……？","ENG":"H-huh...?","TWN":"呃、呃……？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"지뢰가 매설되어 있었다고?","JPN":"地雷が埋もれていたのか？","ENG":"There were mines planted?","TWN":"你說埋著地雷？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"대 침식전에서 꼴사나운 짓은 대개 죽음과 연결됩니다.","JPN":"対侵食戦でそのような醜態を晒すと、大体死にますよ。","ENG":"In the Anti-Corruption War, sloppy behavior usually gets you killed.","TWN":"在大侵蝕戰中，醜陋的行為大多與死亡有關。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"본래라면 죽든 말든 신경 안 쓰고 제 일에 집중하겠지만…….","JPN":"本来ならあなたが死のうが生きようが、仕事に集中したいところですが……","ENG":"Normally I wouldn't care and just mind my own job, but...","TWN":"原本我不會管你死活，只會專注在我自己的任務……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"이번 임무는 최대한 많은 사람이 살아남는 게 유리하니까요.","JPN":"今回の任務は、なるべく多くの人が生き残ったほうが有利ですから。","ENG":"This time, the mission benefits from keeping as many people alive as possible.","TWN":"但這次的任務是讓更多人活下來比較有利。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"대 침식전을 선도하는 알파트릭스 이노베이션의 김초원이라고 합니다.","JPN":"私は対侵食戦をリードするアルファトリックス・イノベーションのスズキ・ナオと申します。","ENG":"I'm Kim Chowon of Alphatrix Innovation, leading the Anti-Corruption War effort.","TWN":"我是領導大侵蝕戰的阿爾法崔克斯改革，金初源。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"빠밤!","JPN":"ジャジャン！","ENG":"Kapow!","TWN":"鏘鏘！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L41_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"……이라고 해야 더 멋있을 것이라 누누이 말했는데.","JPN":"……と言ったほうが格好いいと、あれほど口にしたのだが。","ENG":"...Didn't I tell you that it sounds way cooler if you say it?","TWN":"……我就說這樣說會比較帥吧。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_DESPAIR"},"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"초원아! 도착하자마자 바로 달려가면 어떡해!","JPN":"ナオ！　着いたからって一人で走っていったらダメじゃない！","ENG":"Chowon! You can't just sprint off the second we arrive!","TWN":"初源！你怎麼可以一到就衝出去？！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"그리고, 알파트릭스 제복은 왜 벗어두고 그 옷을 입은 건데?","JPN":"あと、その服は何？　アルファトリックスの制服はどうしたの？","ENG":"And why did you ditch the Alphatrix uniform for that?","TWN":"還有為什麼你脫掉阿爾法崔克斯的制服，穿了那身衣服？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"사막에서 이 복장이 더 어울리거든. 그 시절의 마음가짐으로 돌아갈 수 있으니까.","JPN":"砂漠ではこの格好のほうが似合いますから。あの頃の気持ちを思い出せますし。","ENG":"This getup fits the desert. It puts me back in the right headspace.","TWN":"因為這套在沙漠比較合適啊，也能讓我找回那時的心境。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"그 시절의 마음가짐……?","JPN":"あの頃の気持ち……？","ENG":"The right headspace...?","TWN":"那時的心境……？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그래. 분노, 복수심, 화약, 달궈진 모래알… 기타 등등.","JPN":"そうです。怒り、復讐心、火薬、熱い砂の粒……などなど。","ENG":"Yeah. Rage, payback, gunpowder, sunbaked sand... the works.","TWN":"對啊。憤怒、報仇、火藥、滾燙的沙粒……之類的。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L3_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"맞아… 사람들을 구해야 하는데 그깟 제복이 무슨 소용이야.","JPN":"そうだね……人を助けるのに、制服はどうでもいいよね。","ENG":"You're right... We're here to save people. Who cares about a uniform.","TWN":"是啦……重要的是救人，那套制服也沒什麼用處。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"좋은 울림이다, 소녀여!","JPN":"素晴らしいセリフだ、少女よ！","ENG":"That resonates nicely, girl!","TWN":"你很有氣勢啊，小姑娘！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_LAUGH"},"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"대장의 선택은 틀린 적이 없었지.","JPN":"隊長の選択は常に正しい。","ENG":"Cap's choices have never been wrong.","TWN":"隊長的選擇每次都是對的。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"우리는 정의로운 대장이 믿는 코핀 컴퍼니를 믿는다!","JPN":"私たちは正義の隊長が信じるコフィンカンパニーを信じる！","ENG":"We trust Coffin Company, because our righteous Cap does!","TWN":"我們相信正義感的隊長信任的科芬公司！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"침식체 제2파! 다가옵니다!","JPN":"侵食体第2波、来ます！","ENG":"Second wave of C.O.s! Incoming!","TWN":"侵蝕體，第2波！正在逼近！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_EARTHQUAKE"},{"id":"L15_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"젠장! 방금 겨우 막아낸 게 끝이 아니라고?!","JPN":"くそ！　さっきもギリギリ止めたのに、まだあるのかよ！？","ENG":"You are kidding me! That last push wasn't the end of it?!","TWN":"可惡！剛剛好不容易才擋住了，竟然還沒結束？！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"이대로라면 아스완은 물론이고 이 방위선 병력도 전멸이야!","JPN":"このままじゃアスワン丸ごと、この防衛線の兵力も全滅だ！","ENG":"At this rate, Aswan will fall and this whole defense line will get wiped out!","TWN":"照這樣下去別說阿斯旺，這條防線的兵力都要全滅了！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"비록 리더가 빠진 2군따리이긴 하지만, 저희도 나름 침식전에는 조예가 깊습니다.","JPN":"リーダーのいない第2軍ではありますが、私たちもそれなりに侵食戦の知識は豊富です。","ENG":"We might not be the A-team without Leader, but we know our Anti-Corruption Wars.","TWN":"雖然我們少了老大只剩2軍，但我們在侵蝕戰方面還是有點心得的。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"게다가 관리국 본부로부터 해당 구역의 항구를 확보해달라는 임무를 받았거든요.","JPN":"それに、管理局本部からこの区域の港を確保してほしいという任務を受けていますので。","ENG":"We were tasked by the Administration HQ to secure the harbor in this sector.","TWN":"而且我們也收到管理局本部要我們確保該區域港口的任務。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"본부에서……?","JPN":"本部から……？","ENG":"From HQ...?","TWN":"本部……？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"그럼 이 숫자로도 저 비스트 타입을 무찌를 수 있다는 건가?","JPN":"じゃ、この人数でもあのビーストタイプを倒せるってことか？","ENG":"Are you saying we can beat that Beast-type with these numbers?","TWN":"那麼就表示靠這些人也能打倒那個像野獸的東西？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"해봐야 알겠지만, 저희도 얌전히 감사만 받았던 건 아니거든요.","JPN":"やってみないと分かりませんが、私たちも大人しく監査を受けていたわけではありません。","ENG":"We will see. We didn't sit around collecting thank-yous.","TWN":"雖然要試了才知道，但也不會白白讓大家感謝我們。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"더 업그레이드된 침식전용 거미 지뢰와 도폭선이라면,","JPN":"よりアップグレードした侵食戦用蜘蛛型地雷と導爆線なら……","ENG":"With upgraded Anti-Corruption spider mines and detonation cords,","TWN":"只要使用升級的侵蝕戰專用蜘蛛地雷和導火線，"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"여러분이 화력을 쏟아부을 틈 정도는 만들 수 있을 거예요.","JPN":"皆さんが火力をつぎ込む隙ぐらいは作れるでしょう。","ENG":"we can at least buy you a window to pour on the firepower.","TWN":"應該能幫各位爭取到火力傾瀉的破口。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"조, 좋아. 그럼 어디 한번 해보자고.","JPN":"よ、よし。やってやろうじゃないか。","ENG":"A-all right. Let's do this.","TWN":"好、好吧！那就試試看吧！"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_NPC_COMPLETE_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"좋아요. 우선 시민들의 안전을 확보하기 위해 항구부터 시작하도록 하죠.","JPN":"まずは市民の安全を確保しましょう。港から始めた方がよさそうですね。","ENG":"Very well. For civilian safety, we start with the harbor.","TWN":"很好。為了保障市民安全，我們先從港口開始。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"저희는 그곳을 기점으로 방위선을 형성할 겁니다.","JPN":"私たちはそこを起点に防衛線を形成するのです。","ENG":"We'll anchor the defense line there.","TWN":"我們會以那裡為據點建立防線。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그럼, 프로모션 스타트.","JPN":"では、プロモーションスタート。","ENG":"Then, Promotion start.","TWN":"那麼，推廣作戰開始。"},"stage":{"bg":"CITY_DESERT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"}]`);export{e as default};